from lxml import etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        root = etree.fromstring(xml_data)
    except etree.XMLSyntaxError:
        return None

    students = root.xpath("//student[username = $user and password = $pw]", user=username, pw=password)
    if not students:
        return None

    student = students[0]
    return {
        'username': student.xpath("username/text()")[0],
        'password': student.xpath("password/text()")[0],
        'name': student.xpath("name/text()")[0],
        'citizenship': student.xpath("citizenship/text()")[0],
        'age': student.xpath("age/text()")[0],
    }

